class StockPriceAdjuster:
    def __init__(self, split_ratio):
        self.split_ratio = split_ratio

    def adjust_prices(self, historical_prices):
        adjusted_prices = []
        for price in historical_prices:
            adjusted_price = price / self.split_ratio
            adjusted_prices.append(adjusted_price)
        return adjusted_prices

def main():
    historical_prices = [100.0, 120.0, 130.0, 140.0, 150.0]
    split_ratio = 2.0

    adjuster = StockPriceAdjuster(split_ratio)
    adjusted_prices = adjuster.adjust_prices(historical_prices)

    print("Historical Prices:")
    print(historical_prices)
    print("Adjusted Prices:")
    print(adjusted_prices)

if __name__ == "__main__":
    main()
